        $newTranslations = json_decode('{\"47\": {\"title\": \"من شرم الشيخ: وادي الوشواش\", \"short_description\": \"وادي الوشواش هو وادٍ صحراوي خلاب بالقرب من شرم الشيخ، يشتهر بتكويناته الصخرية الرائعة، وإطلالاته المذهلة على جبال سيناء، والحياة البرية الصحراوية الغنية. وجهة مثالية لعشاق الطبيعة والمشي والمغامرة.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>وادي الوشواش هو وادٍ طبيعي مذهل يقع في قلب شبه جزيرة سيناء، على بعد مسافة قصيرة بالسيارة من شرم الشيخ. يوفر هذا الكنز المخفي مزيجًا رائعًا من المناظر الطبيعية الخلابة، والمعجزات الجيولوجية، والمغامرة الصحراوية الأصيلة. يتميز الوادي، الذي نحتته الطبيعة على مدى آلاف السنين، بمنحدرات الحجر الرملي الشاهقة، والأخاديد الضيقة، والتكوينات الصخرية الفريدة التي تشكل منظرًا صحراويًا رائعًا. يمكن للزوار الاستمتاع بالمشي لمسافات طويلة على طول الممرات الخلابة، ورصد الحياة البرية الصحراوية مثل الغزلان والوعل والثعالب، والاستمتاع بالمناظر البانورامية لجبال سيناء المهيبة. بالإضافة إلى المشي لمسافات طويلة، توفر المنطقة مجموعة متنوعة من الأنشطة المثيرة بما في ذلك رحلات السفاري بالسيارات الجيب، وقيادة الدراجات الرباعية (كواد)، وركوب الجمال والخيل، مما يجعلها وجهة إيجابية للغاية لعشاق المغامرة والباحثين عن الهدوء في الطبيعة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>استمتع بمحمية وادي الوشواش الطبيعية، أحد أجمل الأخاديد الجبلية في سيناء.</li>\\n  <li>المشي لمسافات طويلة واستكشاف البحيرة السرية الدافئة بين الصخور الشاهقة.</li>\\n  <li>انتقالات مريحة بالسيارات الجيب 4x4 من وإلى فندقك بشرم الشيخ.</li>\\n  <li>التقاط صور مذهلة للمناظر الطبيعية الجبلية الفريدة.</li>\\n</ul>\", \"included\": [\"الاستقبال والتوصيل بسيارة 4x4 مريحة\", \"مرشد سياحي محلي محترف\", \"زجاجة مياه معدنية\"], \"excluded\": [\"المشروبات الإضافية في الكافتيريا البدوية\", \"المصاريف الشخصية والإكراميات\", \"الأنشطة الاختيارية (ركوب الجمال أو دراجات كواد)\"]}, \"48\": {\"title\": \"دهب والوادي الملون\", \"short_description\": \"اكتشف جمال سيناء الساحر في رحلة يوم كامل إلى الوادي الملون ومدينة دهب. استمتع بالمشي بين الصخور الملونة، وقيادة الكواد في الصحراء، والسباحة بجوار البلو هول الشهير، وركوب الجمال على الشاطئ مع غداء بدوي شهي.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>انطلق في مغامرة شيقة تجمع بين جمال الصحراء وسحر البحر الأحمر. تبدأ الرحلة بالانتقال من فندقك بشرم الشيخ صباحًا نحو الوادي الملون، حيث تمشي بين الممرات الصخرية الضيقة وتتأمل التكوينات الرملية الملونة التي شكلتها الرياح والأمطار على مر العصور. بعد ذلك، تخوض تجربة قيادة البيتش باجي الحماسية في دروب الصحراء. ثم نتوجه إلى شاطئ مدينة دهب للاستمتاع بركوب الجمال على طول الساحل، تليها وقفة للسباحة والسنوركل في المياه الفيروزية الساحرة بجوار منطقة البلو هول العالمية لمشاهدة الشعاب المرجانية والأسماك الملونة. يتم تقديم غداء بدوي لذيذ على البحر مباشرة، مع وقت حر للتسوق في بازارات مدينة دهب لشراء الهدايا التذكارية والأعشاب الطبيعية قبل العودة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>استكشاف الوادي الملون والتكوينات الصخرية الفريدة في سيناء.</li>\\n  <li>قيادة البيتش باجي (كواد) في الصحراء المفتوحة.</li>\\n  <li>ركوب الجمال على الشاطئ الفيروزي لمدينة دهب الرائعة.</li>\\n  <li>السنوركل والسباحة بجوار منطقة البلو هول الشهيرة عالميًا.</li>\\n  <li>تناول وجبة غداء بدوي شهي على البحر ووقت حر للتسوق في دهب.</li>\\n</ul>\", \"included\": [\"الاستقبال والتوصيل من وإلى الفندق بشرم الشيخ\", \"مغامرة قيادة الكواد (البيتش باجي) بالصحراء\", \"المشي بصحبة مرشد في الوادي الملون\", \"ركوب الجمال على شاطئ دهب\", \"وجبة غداء شهية على شاطئ البحر الأحمر\", \"السباحة والسنوركل بجوار منطقة البلو هول\"], \"excluded\": [\"أدوات السنوركل (الماسك والزعانف)\", \"رسوم دخول محمية البلو هول (10 دولار للفرد)\", \"المشروبات في المطعم والمصاريف الشخصية\", \"الإكراميات\"]}, \"49\": {\"title\": \"رحلة الغواصة واليخت الزجاجي\", \"short_description\": \"رحلة عائلية ممتعة ومريحة لجميع الأعمار لمشاهدة عجائب البحر الأحمر والشعاب المرجانية والأسماك الملونة من خلال النوافذ الزجاجية البانورامية الكبيرة للغواصة دون الحاجة للبلل.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>استمتع برحلة بحرية رائعة ومناسبة جدًا للعائلات والأطفال وكبار السن على متن اليخت الزجاجي (الغواصة). تتيح لك هذه الرحلة مشاهدة الحدائق المرجانية المذهلة والشعاب الملونة والأسماك النادرة للبحر الأحمر في خليج نعمة ومحمية رأس محمد من خلال نوافذ زجاجية بانورامية كبيرة في الطابق السفلي تحت الماء على عمق يصل إلى 3 أمتار. يمكنك الجلوس في مقاعد مريحة ومكيفة والاستمتاع بالمشاهدة الفريدة بينما يقدم لك المرشد شرحًا عن الكائنات البحرية المتنوعة. كما يمكنك الصعود إلى السطح العلوي المفتوح للاستمتاع بنسيم البحر والشمس والمناظر الطبيعية الخلابة لساحل شرم الشيخ والتقاط أجمل الصور التذكارية.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>رؤية واضحة وبانورامية للشعاب المرجانية والأسماك النادرة دون الحاجة للسباحة أو الغوص.</li>\\n  <li>مناسبة جدًا للأطفال والرضع وكبار السن وغير السباحين.</li>\\n  <li>يخت مجهز بنوافذ زجاجية مكيفة في طابق الأعماق وسطح مفتوح للاستجمام.</li>\\n  <li>انتقالات مريحة وسريعة من وإلى فندقك بشرم الشيخ.</li>\\n</ul>\", \"included\": [\"الاستقبال والتوصيل من وإلى الفندق داخل شرم الشيخ\", \"تذكرة دخول الغواصة واليخت الزجاجي\", \"مشروب ترحيبي أو زجاجة مياه معدنية\"], \"excluded\": [\"المشروبات الإضافية والمأكولات على متن اليخت\", \"المصاريف الشخصية والإكراميات\"]}, \"50\": {\"title\": \"من الغردقة: رحلة الأقصر ووادي الملكات (بالأتوبيس)\", \"short_description\": \"اكتشف عظمة الفراعنة في رحلة يوم كامل من الغردقة إلى الأقصر بالأتوبيس المشترك. تشمل زيارة معبد الكرنك الضخم، ومقابر وادي الملكات، ومعبد حتشبسوت الجنائزي، وتمثالي ممنون مع تناول الغداء.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>سافر عبر الزمن واكتشف مدينة طيبة القديمة (الأقصر)، العاصمة الفرعونية العظيمة، في رحلة مميزة من الغردقة. تبدأ الرحلة بزيارة معبد الكرنك التاريخي، أكبر دور عبادة في العالم القديم، لتأمل بهو الأعمدة الضخم والمسلات الشاهقة. بعد تناول وجبة الغداء، نعبر إلى البر الغربي لنهر النيل لاستكشاف وادي الملكات، حيث ترقد ملكات وأميرات الفراعنة في مقابر منحوتة في الصخر ومزينة برسومات ملونة رائعة. تلي ذلك زيارة المعبد الجنائزي الفريد للملكة حتشبسوت في الدير البحري، وهو تحفة معمارية منحوتة في حضن الجبل. وأخيرًا، نتوقف لالتقاط الصور أمام تمثالي ممنون العملاقين للملك أمنحتب الثالث قبل رحلة العودة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة مجمع معابد الكرنك العظيم في البر الشرقي للأقصر.</li>\\n  <li>استكشاف المقابر الملكية الرائعة في وادي الملكات بالبر الغربي.</li>\\n  <li>زيارة معبد الملكة حتشبسوت الفريد المنحوت في الصخر بالدير البحري.</li>\\n  <li>التوقف أمام تمثالي ممنون الشهيرين وسماع تاريخ طيبة القديم من مرشد متخصص.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"الانتقال من وإلى الفندق بالغردقة بأتوبيس سياحي مكيف ومريح\", \"مرشد سياحي متخصص في علم المصريات ومترجم\", \"تذاكر الدخول لجميع المعالم المذكورة (معبد الكرنك، وادي الملكات، معبد حتشبسوت)\", \"وجبة غداء لذيذة في مطعم محلي بالأقصر\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"جولة الفلوكة الاختيارية في النيل وزيارة جزيرة الموز\", \"رسوم التصوير داخل المقابر الأثرية\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للفرد\"]}, \"51\": {\"title\": \"من الغردقة: رحلة الأقصر ووادي الملكات (سيارة خاصة هايس)\", \"short_description\": \"استمتع برحلة خاصة مريحة ومرنة بالكامل مع عائلتك أو أصدقائك في سيارة تويوتا هايس خاصة من الغردقة إلى الأقصر. تشمل زيارة معبد الكرنك، مقابر وادي الملكات، معبد حتشبسوت، وتمثالي ممنون مع غداء فاخر.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>سافر عبر الزمن واكتشف مدينة طيبة القديمة (الأقصر)، العاصمة الفرعونية العظيمة، في رحلة مميزة من الغردقة. تبدأ الرحلة بزيارة معبد الكرنك التاريخي، أكبر دور عبادة في العالم القديم، لتأمل بهو الأعمدة الضخم والمسلات الشاهقة. بعد تناول وجبة الغداء، نعبر إلى البر الغربي لنهر النيل لاستكشاف وادي الملكات، حيث ترقد ملكات وأميرات الفراعنة في مقابر منحوتة في الصخر ومزينة برسومات ملونة رائعة. تلي ذلك زيارة المعبد الجنائزي الفريد للملكة حتشبسوت في الدير البحري، وهو تحفة معمارية منحوتة في حضن الجبل. وأخيرًا، نتوقف لالتقاط الصور أمام تمثالي ممنون العملاقين للملك أمنحتب الثالث قبل رحلة العودة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة مجمع معابد الكرنك العظيم في البر الشرقي للأقصر.</li>\\n  <li>استكشاف المقابر الملكية الرائعة في وادي الملكات بالبر الغربي.</li>\\n  <li>زيارة معبد الملكة حتشبسوت الفريد المنحوت في الصخر بالدير البحري.</li>\\n  <li>التوقف أمام تمثالي ممنون الشهيرين وسماع تاريخ طيبة القديم من مرشد متخصص.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"انتقالات خاصة ذهابًا وإيابًا بسيارة تويوتا هايس الحديثة والمكيفة\", \"مرشد سياحي خاص مرخص في علم المصريات يرافقكم بالكامل\", \"تذاكر الدخول للمزارات الأثرية (الكرنك، وادي الملكات، معبد حتشبسوت)\", \"وجبة غداء فاخرة في مطعم متميز على النيل\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"جولة الفلوكة الاختيارية في النيل وزيارة جزيرة الموز\", \"رسوم التصوير داخل المقابر الأثرية\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للشخص\"]}, \"52\": {\"title\": \"من الغردقة: رحلة الأقصر ووادي الملوك (بالأتوبيس)\", \"short_description\": \"رحلة يوم كامل بالأتوبيس المشترك من الغردقة لاستكشاف الأقصر التاريخية. تشمل مقابر وادي الملوك الشهيرة، معبد الكرنك العظيم، معبد حتشبسوت بالدير البحري، وتمثالي ممنون مع تناول الغداء.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>استكشف العاصمة الأثرية الأغنى في العالم، الأقصر، في جولة فريدة تأخذك إلى مهد الحضارة الفرعونية. تبدأ الرحلة بزيارة معبد الكرنك الضخم في البر الشرقي لنهر النيل لتأمل بهو الأعمدة والمسلات الشاهقة. بعد تناول وجبة الغداء، نتوجه إلى البر الغربي لعبور النيل وزيارة وادي الملوك الشهير عالميًا، حيث استكشف مقابر الفراعنة العظام مثل رمسيس وتوت عنخ آمون المليئة بالنقوش والألوان الرائعة. تليها زيارة معبد الملكة حتشبسوت الجنائزي المذهل في الدير البحري، المنحوت بالكامل في الجبل. وفي نهاية الجولة، نتوقف لالتقاط الصور أمام تمثالي ممنون الشهيرين اللذين يحرسان معبد أمنحتب الثالث قبل العودة إلى الغردقة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة مجمع معابد الكرنك العظيم في البر الشرقي للأقصر.</li>\\n  <li>استكشاف المقابر الملكية المحفورة في الصخر بوادي الملوك في البر الغربي.</li>\\n  <li>زيارة معبد الملكة حتشبسوت الفريد المنحوت في الصخر بالدير البحري.</li>\\n  <li>التوقف أمام تمثالي ممنون الشهيرين وسماع تاريخ طيبة القديم من مرشد متخصص.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"الاستقبال والتوصيل من وإلى الفندق بالغردقة بأتوبيس سياحي مكيف ومريح\", \"مرشد سياحي متخصص في علم المصريات ومترجم\", \"تذاكر الدخول لجميع المعالم المذكورة (معبد الكرنك، وادي الملوك لـ 3 مقابر، معبد حتشبسوت)\", \"وجبة غداء لذيذة في مطعم محلي بالأقصر\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"تذاكر الدخول الإضافية لمقبرة الملك توت عنخ آمون أو سيتي الأول\", \"جولة الفلوكة الاختيارية في النيل وزيارة جزيرة الموز\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للفرد\"]}, \"53\": {\"title\": \"من الغردقة: رحلة الأقصر ووادي الملوك (سيارة خاصة هايس)\", \"short_description\": \"جولة خاصة فاخرة ومرنة ومريحة بسيارة تويوتا هايس خاصة من الغردقة إلى الأقصر. استكشف مقابر وادي الملوك، معبد الكرنك، معبد حتشبسوت، وتمثالي ممنون مع مرشد سياحي خاص وغداء متميز.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>استكشف العاصمة الأثرية الأغنى في العالم، الأقصر، في جولة فريدة تأخذك إلى مهد الحضارة الفرعونية. تبدأ الرحلة بزيارة معبد الكرنك الضخم في البر الشرقي لنهر النيل لتأمل بهو الأعمدة والمسلات الشاهقة. بعد تناول وجبة الغداء، نتوجه إلى البر الغربي لعبور النيل وزيارة وادي الملوك الشهير عالميًا، حيث استكشف مقابر الفراعنة العظام مثل رمسيس وتوت عنخ آمون المليئة بالنقوش والألوان الرائعة. تليها زيارة معبد الملكة حتشبسوت الجنائزي المذهل في الدير البحري، المنحوت بالكامل في الجبل. وفي نهاية الجولة، نتوقف لالتقاط الصور أمام تمثالي ممنون الشهيرين اللذين يحرسان معبد أمنحتب الثالث قبل العودة إلى الغردقة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة مجمع معابد الكرنك العظيم في البر الشرقي للأقصر.</li>\\n  <li>استكشاف المقابر الملكية المحفورة في الصخر بوادي الملوك في البر الغربي.</li>\\n  <li>زيارة معبد الملكة حتشبسوت الفريد المنحوت في الصخر بالدير البحري.</li>\\n  <li>التوقف أمام تمثالي ممنون الشهيرين وسماع تاريخ طيبة القديم من مرشد متخصص.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"انتقالات خاصة ذهابًا وإيابًا بسيارة تويوتا هايس الحديثة والمكيفة\", \"مرشد سياحي خاص مرخص في علم المصريات يرافقكم بالكامل\", \"تذاكر الدخول للمزارات الأثرية (الكرنك، وادي الملوك لـ 3 مقابر، معبد حتشبسوت)\", \"وجبة غداء فاخرة في مطعم متميز على النيل\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"تذاكر الدخول الإضافية لمقبرة الملك توت عنخ آمون أو سيتي الأول\", \"جولة الفلوكة الاختيارية في النيل وزيارة جزيرة الموز\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للشخص\"]}, \"54\": {\"title\": \"رحلة اليوم الكامل من الغردقة إلى القاهرة والأهرامات والمتحف (بالأتوبيس)\", \"short_description\": \"رحلة يوم كامل بالأتوبيس المشترك من الغردقة لاستكشاف معالم القاهرة العريقة. تشمل الأهرامات الثلاثة وأبو الهول، والمتحف المصري بالتحرير، مع غداء لذيذ ومرشد متخصص.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>اكتشف عجائب الدنيا القديمة وعظمة القاهرة الفرعونية في رحلة يوم كامل من الغردقة. تبدأ الرحلة بزيارة المتحف المصري الشهير في ميدان التحرير، والذي يضم أكثر من 120,000 قطعة أثرية فريدة بما في ذلك كنوز الملك الشاب توت عنخ آمون وقناعه الذهبي الشهير. بعد الاستمتاع بغداء شهي في مطعم محلي، نتوجه إلى هضبة الجيزة للوقوف أمام الأهرامات الثلاثة العظيمة (خوفو وخفرع ومنقرع)، رمز الهندسة المصرية القديمة وعجائب العالم القديم الوحيدة الباقية. سنستمع لشرح مفصل من المرشد حول تاريخ بنائها، ثم ننتقل لزيارة معبد الوادي وتمثال أبو الهول العظيم المنحوت من صخرة واحدة قبل التوقف في بازارات البردي والعطور وبدء طريق العودة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة المتحف المصري القديم بالتحرير لمشاهدة الآثار الفرعونية النادرة.</li>\\n  <li>الوقوف أمام أهرامات الجيزة الثلاثة العظيمة وتأمل إبداع البناء الفراعنة.</li>\\n  <li>زيارة تمثال أبو الهول العظيم ومعبد الوادي والتقاط أجمل الصور التذكارية.</li>\\n  <li>مرشد سياحي محترف في علم المصريات يرافقكم طوال الجولة.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"الاستقبال والتوصيل من وإلى الفندق بالغردقة بأتوبيس سياحي مكيف ومريح\", \"مرشد سياحي متخصص في علم المصريات ومترجم\", \"تذاكر الدخول لجميع المعالم المذكورة (المتحف المصري بالتحرير، أهرامات الجيزة، تمثال أبو الهول)\", \"وجبة غداء لذيذة في مطعم محلي بالقاهرة\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"تذاكر الدخول الإضافية لداخل الهرم الأكبر أو قاعة المومياوات\", \"جولة الفلوكة الاختيارية في نهر النيل\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للفرد\"]}, \"55\": {\"title\": \"رحلة اليوم الكامل من الغردقة إلى القاهرة والأهرامات والمتحف (سيارة خاصة هايس)\", \"short_description\": \"رحلة خاصة فاخرة ومرنة ومريحة بسيارة تويوتا هايس خاصة من الغردقة إلى القاهرة. استمتع بزيارة أهرامات الجيزة، أبو الهول، والمتحف المصري بالتحرير بصحبة مرشدك الخاص وغداء متميز.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>اكتشف عجائب الدنيا القديمة وعظمة القاهرة الفرعونية في رحلة يوم كامل من الغردقة. تبدأ الرحلة بزيارة المتحف المصري الشهير في ميدان التحرير، والذي يضم أكثر من 120,000 قطعة أثرية فريدة بما في ذلك كنوز الملك الشاب توت عنخ آمون وقناعه الذهبي الشهير. بعد الاستمتاع بغداء شهي في مطعم محلي، نتوجه إلى هضبة الجيزة للوقوف أمام الأهرامات الثلاثة العظيمة (خوفو وخفرع ومنقرع)، رمز الهندسة المصرية القديمة وعجائب العالم القديم الوحيدة الباقية. سنستمع لشرح مفصل من المرشد حول تاريخ بنائها، ثم ننتقل لزيارة معبد الوادي وتمثال أبو الهول العظيم المنحوت من صخرة واحدة قبل التوقف في بازارات البردي والعطور وبدء طريق العودة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة المتحف المصري القديم بالتحرير لمشاهدة الآثار الفرعونية النادرة.</li>\\n  <li>الوقوف أمام أهرامات الجيزة الثلاثة العظيمة وتأمل إبداع البناء الفراعنة.</li>\\n  <li>زيارة تمثال أبو الهول العظيم ومعبد الوادي والتقاط أجمل الصور التذكارية.</li>\\n  <li>مرشد سياحي محترف في علم المصريات يرافقكم طوال الجولة.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"انتقالات خاصة ذهابًا وإيابًا بسيارة تويوتا هايس الحديثة والمكيفة\", \"مرشد سياحي خاص مرخص في علم المصريات يرافقكم بالكامل\", \"تذاكر الدخول للمزارات الأثرية (المتحف المصري، أهرامات الجيزة، تمثال أبو الهول)\", \"وجبة غداء فاخرة في مطعم متميز\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"تذاكر الدخول الإضافية لداخل الهرم الأكبر أو قاعة المومياوات\", \"جولة الفلوكة الاختيارية في نهر النيل\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للشخص\"]}, \"56\": {\"title\": \"رحلة القاهرة والمتحف المصري الكبير (GEM) وأهرامات الجيزة (بالأتوبيس)\", \"short_description\": \"رحلة يوم كامل بالأتوبيس المشترك من الغردقة لزيارة المتحف المصري الكبير (GEM) الحديث، وأهرامات الجيزة العظيمة، وتمثال أبو الهول، مع وجبة غداء لذيذة ومرشد متخصص.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>كن من الأوائل الذين يستكشفون الصرح الأثري الأحدث والأعظم عالميًا، المتحف المصري الكبير (GEM)، في رحلة يوم كامل استثنائية من الغردقة. يضم هذا المتحف الحديث للغاية تحفًا هندسية وكنوزًا أثرية فرعونية لا مثيل لها بما في ذلك المجموعة الكاملة لآثار الملك توت عنخ آمون. بعد جولتنا بالمتحف، نتناول غداءً شهيًا في مطعم بالقاهرة، ثم نتوجه إلى هضبة الجيزة التاريخية للوقوف أمام الأهرامات العظيمة خوفو وخفرع ومنقرع. سنستمع إلى شرح المرشد حول أسرار بناء الأهرامات وتاريخ الملوك الفراعنة، ونزور تمثال أبو الهول العظيم ومعبد الوادي، مع وقفة اختيارية في بازارات البردي والعطور قبل بدء رحلة العودة الفاخرة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة المتحف المصري الكبير (GEM) صرح الآثار الأحدث والأكبر في العالم.</li>\\n  <li>الوقوف أمام أهرامات الجيزة الثلاثة العظيمة وتأمل إبداع البناء الفراعنة.</li>\\n  <li>زيارة تمثال أبو الهول العظيم ومعبد الوادي والتقاط أجمل الصور التذكارية.</li>\\n  <li>مرشد سياحي محترف في علم المصريات يرافقكم طوال الجولة.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"الاستقبال والتوصيل من وإلى الفندق بالغردقة بأتوبيس سياحي مكيف ومريح\", \"مرشد سياحي متخصص في علم المصريات ومترجم\", \"تذاكر الدخول لجميع المعالم المذكورة (المتحف المصري الكبير، أهرامات الجيزة، تمثال أبو الهول)\", \"وجبة غداء لذيذة في مطعم محلي بالقاهرة\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"تذاكر الدخول الإضافية لداخل الهرم الأكبر أو المعارض الخاصة داخل المتحف الكبير\", \"جولة الفلوكة الاختيارية في نهر النيل\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للفرد\"]}, \"57\": {\"title\": \"رحلة القاهرة والمتحف المصري الكبير (GEM) وأهرامات الجيزة (سيارة خاصة هايس)\", \"short_description\": \"جولة خاصة فاخرة ومريحة بسيارة تويوتا هايس من الغردقة لزيارة المتحف المصري الكبير (GEM) الأحدث عالميًا، وأهرامات الجيزة، وأبو الهول بصحبة مرشد خاص وغداء فاخر.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>كن من الأوائل الذين يستكشفون الصرح الأثري الأحدث والأعظم عالميًا، المتحف المصري الكبير (GEM)، في رحلة يوم كامل استثنائية من الغردقة. يضم هذا المتحف الحديث للغاية تحفًا هندسية وكنوزًا أثرية فرعونية لا مثيل لها بما في ذلك المجموعة الكاملة لآثار الملك توت عنخ آمون. بعد جولتنا بالمتحف، نتناول غداءً شهيًا في مطعم بالقاهرة، ثم نتوجه إلى هضبة الجيزة التاريخية للوقوف أمام الأهرامات العظيمة خوفو وخفرع ومنقرع. سنستمع إلى شرح المرشد حول أسرار بناء الأهرامات وتاريخ الملوك الفراعنة، ونزور تمثال أبو الهول العظيم ومعبد الوادي، مع وقفة اختيارية في بازارات البردي والعطور قبل بدء رحلة العودة الفاخرة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة المتحف المصري الكبير (GEM) صرح الآثار الأحدث والأكبر في العالم.</li>\\n  <li>الوقوف أمام أهرامات الجيزة الثلاثة العظيمة وتأمل إبداع البناء الفراعنة.</li>\\n  <li>زيارة تمثال أبو الهول العظيم ومعبد الوادي والتقاط أجمل الصور التذكارية.</li>\\n  <li>مرشد سياحي محترف في علم المصريات يرافقكم طوال الجولة.</li>\\n  <li>تناول وجبة غداء لذيذة متضمنة في الرحلة لضمان راحتكم بالكامل.</li>\\n</ul>\", \"included\": [\"انتقالات خاصة ذهابًا وإيابًا بسيارة تويوتا هايس الحديثة والمكيفة\", \"مرشد سياحي خاص مرخص في علم المصريات يرافقكم بالكامل\", \"تذاكر الدخول للمزارات الأثرية (المتحف المصري الكبير، أهرامات الجيزة، تمثال أبو الهول)\", \"وجبة غداء فاخرة في مطعم متميز\"], \"excluded\": [\"المشروبات في المطعم والمصاريف الشخصية\", \"تذاكر الدخول الإضافية لداخل الهرم الأكبر أو المعارض الخاصة داخل المتحف الكبير\", \"جولة الفلوكة الاختيارية في نهر النيل\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للشخص\"]}, \"58\": {\"title\": \"جولة معالم مدينة الغردقة\", \"short_description\": \"اكتشف سحر الغردقة الحقيقي في جولة لزيارة مسجد الميناء الكبير، وكاتدرائية أقباط مارجرجس، والبلد القديم (الدهار) وسوق السمك النابض بالحياة، ومارينا اليخوت الحديثة مع فرصة ممتازة للتسوق.\", \"included\": [\"الاستقبال والتوصيل من وإلى الفندق بالغردقة بالسيارة الخاصة\", \"مرشد سياحي مرافق لشرح المعالم وتاريخ المدينة\", \"زجاجة مياه معدنية باردة أثناء الجولة\"], \"excluded\": [\"المأكولات والمشروبات الإضافية\", \"الهدايا التذكارية والمصاريف الشخصية والمشتريات من الأسواق\", \"الإكراميات\", \"رسوم انتقال إضافية للمناطق البعيدة (الجونة، مكادي باي، سهل حشيش، سفاجا) بقيمة 10 دولار للشخص\"], \"description\": \"<h3>نظرة عامة</h3>\\n<p>عش تجربة التباين النابض بالحياة في مدينة الغردقة في هذه الجولة الخاصة التي تستغرق 4 ساعات، والتي تجمع بين التراث الثقافي للمدينة والتقاليد المحلية والمعالم السياحية الحديثة. سافر براحة في سيارة مكيفة مع خدمة الاستقبال والتوصيل من وإلى الفندق، بينما يشاركك مرشدك المحترف معلومات رائعة حول تاريخ المدينة وحياتها اليومية. قم بزيارة بعض أبرز معالم الغردقة، بما في ذلك مسجد الميناء الجميل وكاتدرائية أقباط مارجرجس الرائعة (الأنبا شنودة). انغمس في الأجواء الأصلية لسوق السمك النابض بالحياة، حيث يتجمع السكان المحليون لتداول الطازج من البحر الأحمر. استمر في زيارة الجانب الحديث من المدينة من خلال نزهة مريحة على طول مارينا الغردقة، المشهورة باليخوت الفاخرة والمقاهي المطلة على الماء والإطلالات الرائعة على البحر. ثم استكشف الدهار، أقدم أحياء الغردقة، حيث تقدم البازارات التقليدية والمحلات التجارية المحلية والشوارع الحيوية لمحة عن الطابع الأصيل للمدينة. تمنحكم هذه الجولة مقدمة شاملة ومثالية للزوار لأول مرة والمسافرين الذين يبحثون عن فهم أعمق للوجهة ومزيج الغردقة الفريد من التاريخ والثقافة والحياة المعاصرة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>زيارة مسجد الميناء الكبير وكاتدرائية الأقباط الشهيرة بالغردقة.</li>\\n  <li>استكشاف الشوارع والبازارات التقليدية في منطقة الدهار القديمة.</li>\\n  <li>تجربة الحياة المحلية في سوق السمك النابض بالحياة.</li>\\n  <li>التنزه في مارينا الغردقة الخلابة المطلة على البحر الأحمر.</li>\\n  <li>الاستمتاع بجولة خاصة مع مرشد سياحي وانتقالات مكيفة من وإلى الفندق.</li>\\n</ul>\"}, \"59\": {\"title\": \"سوبر سفاري الصحراء مرسى علم\", \"short_description\": \"أفضل مغامرة سفاري في مرسى علم! قيادة البيتش باجي (كواد)، ركوب الجمال، وزيارة القرية البدوية وتناول عشاء باربكيو لذيذ مع حفل استعراضي وبدوي تحت النجوم.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>انطلق في رحلة سفاري صحراوية متكاملة ومثيرة في قلب صحراء مرسى علم الشرقية. تبدأ الرحلة بالانتقال بالسيارات ذات الدفع الرباعي إلى محطة السفاري، حيث تتلقى إرشادات السلامة وتبدأ مغامرة قيادة البيتش باجي (الرباعي) وسط الوديان والتلال الرملية الذهبية. نصل بعد ذلك إلى القرية البدوية الأصيلة للتعرف على نمط الحياة والتقاليد المحلية وتناول شاي الضيافة البدوي المميز، مع تجربة ركوب الجمال والتقاط صور تذكارية رائعة بملابس بدوية. وعند غروب الشمس، نصعد التل لمشاهدة المنظر البانورامي الساحر للغروب خلف جبال البحر الأحمر. وينتهي اليوم الممتع بتناول عشاء باربكيو لذيذ والاستمتاع بفقرات الحفل الاستعراضي والموسيقى البدوية تحت سماء الصحراء الصافية المليئة بالنجوم قبل العودة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>مغامرة قيادة البيتش باجي (كواد) في صحراء مرسى علم الجميلة.</li>\\n  <li>زيارة قرية بدوية وتجربة الضيافة البدوية وركوب الجمال التقليدية.</li>\\n  <li>مشاهدة غروب الشمس الرائع من أعلى تلال الصحراء الشرقية.</li>\\n  <li>تناول عشاء بوفيه باربكيو شهي والاستمتاع بالعروض الترفيهية الحية.</li>\\n  <li>انتقالات مريحة ومباشرة من وإلى فندقك بمرسى علم بسيارات 4x4.</li>\\n</ul>\", \"included\": [\"الانتقال من وإلى الفندق بمرسى علم بسيارات 4x4\", \"قيادة دراجات البيتش باجي (الرباعية) بصحبة مرشد\", \"زيارة القرية البدوية وركوب الجمال البدوية التقليدية\", \"عشاء بوفيه مفتوح باربكيو ومشروب غازي ومياه معدنية\", \"الحفل البدوي والعروض الاستعراضية والشرقية\"], \"excluded\": [\"النظارات الشمسية والوشاح (اللفة البدوية)\", \"المشروبات الإضافية والمشتريات الشخصية\", \"الإكراميات\"]}, \"60\": {\"title\": \"رحلة سفاري علاء الدين في مرسى علم\", \"short_description\": \"رحلة سفاري صباحية شيقة في صحراء مرسى علم. تشمل قيادة البيتش باجي، ركوب الجيب إلى قرية مناجم الذهب القديمة المهجورة، تناول الفطور البدوي الطازج وركوب الجمال والتعرف على طريقة خبز العيش البدوية.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>استكشف أسرار وتاريخ الصحراء الشرقية في مغامرة سفاري صباحية فريدة من نوعها بمرسى علم. تبدأ الرحلة بالانتقال بالسيارات ذات الدفع الرباعي للوصول لمحطة السفاري (Camel Yard)، حيث تخوض جولة قيادة حماسية بالبيتش باجي لمدة 30 دقيقة. بعد ذلك، ننطلق بالسيارة الجيب وسط الوديان الجبلية الشاهقة للتوجه نحو قرية التعدين القديمة المهجورة واستكشاف مناجم الذهب الأثرية والتعرف على تاريخ استخراج الكنوز من جبال البحر الأحمر. نعود بعدها لساحة الجمال لتناول وجبة فطور مصري بدوي طازج وشهي مع الخبز الساخن والشاي الدافئ. كما ستستمتع بركوب الجمل البدوية ومشاهدة السيدات البدويات وهن يخبزن العيش البلدي بالطريقة التقليدية قبل العودة للفندق.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>مغامرة قيادة البيتش باجي (كواد) وجولة جيب وسط الجبال والوديان.</li>\\n  <li>استكشاف قرية التعدين ومناجم الذهب المهجورة الأثرية وسماع تاريخها.</li>\\n  <li>تناول وجبة فطور مصري بدوي طازج ولذيذ في ساحة الجمال.</li>\\n  <li>ركوب الجمل وتجربة خبز العيش البدوية التقليدية والتفاعل مع الحياة البدوية.</li>\\n  <li>انتقالات مريحة ومباشرة من وإلى فندقك بمرسى علم.</li>\\n</ul>\", \"included\": [\"الانتقال من وإلى الفندق بمرسى علم بسيارات 4x4\", \"قيادة دراجات البيتش باجي (الرباعية) لمدة 30 دقيقة\", \"جولة بالسيارة الجيب وسط الصحراء لقرية المناجم\", \"زيارة مناجم الذهب القديمة المهجورة ومعالم القرية\", \"وجبة فطور مصري بدوي طازج وشاي بدوي دافئ\", \"ركوب الجمل وتجربة خبز العيش البدوية\"], \"excluded\": [\"النظارات الشمسية والوشاح البدوية\", \"المصاريف الشخصية والمشروبات الإضافية\", \"الإكراميات\"]}, \"61\": {\"title\": \"رحلة موتو مارين (بيتش باجي وبحيرة شاطئية) في مرسى علم\", \"short_description\": \"مزيج رائع من مغامرة الصحراء وجمال البحر! قيادة البيتش باجي للوصول إلى بحيرة شاطئية خاصة للسباحة والسنوركل لاستكشاف السلاحف البحرية، ثم تناول غداء السمك الطازج في ساحة الجمال.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>اجمع بين إثارة الصحراء وسحر البحر الأحمر في مغامرة (موتو مارين) الحصرية بمرسى علم. تبدأ الرحلة بالانتقال من الفندق إلى ساحة الجمال (Camel Yard) لتجهيز دراجات البيتش باجي (الرباعي). ننطلق بالدراجات عبر دروب الصحراء والوديان باتجاه خط الساحل للوصول إلى بحيرة شاطئية هادئة وخاصة. هناك، نستمتع بالسباحة والسنوركل في المياه الفيروزية الكريستالية الصافية لمشاهدة الشعاب المرجانية والأسماك الاستوائية ومراقبة السلاحف البحرية النادرة في موئلها الطبيعي. بعد وقفة البحر، نعود بالدراجات إلى ساحة الجمال للاستراحة وتناول وجبة غداء شهية ومميزة من السمك الطازج المشوي مع الأرز والسلطات المتنوعة، والاستمتاع بتناول الشاي البدوي الدافئ في أجواء بدوية دافئة قبل التوصيل للفندق.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>مغامرة قيادة البيتش باجي (كواد) في مسارات الصحراء والساحل.</li>\\n  <li>السباحة والسنوركل في بحيرة شاطئية هادئة وخاصة ومراقبة السلاحف البحرية.</li>\\n  <li>تناول غداء السمك المشوي الطازج اللذيذ والأرز في ساحة الجمال.</li>\\n  <li>الاستمتاع بتناول الشاي البدوي والاسترخاء في أجواء المخيم البدوي المميزة.</li>\\n  <li>انتقالات مريحة ومباشرة من وإلى فندقك بمرسى علم.</li>\\n</ul>\", \"included\": [\"الانتقال من وإلى الفندق بمرسى علم بسيارات 4x4\", \"قيادة دراجات البيتش باجي (الرباعية) للبحيرة والعودة\", \"وقفة السباحة والسنوركل في البحيرة الشاطئية الخاصة\", \"وجبة غداء شهية من السمك الطازج المشوي والأرز والسلطات بساحة الجمال\", \"شاي بدوي دافئ ومياه معدنية متضمنة\"], \"excluded\": [\"النظارات الشمسية والوشاح البدوي\", \"أدوات السنوركل (الماسك والزعانف) للرحلة البحرية\", \"المأكولات الإضافية والمشتريات والمشروبات الغازية\", \"طباعة الصور التذكارية على ورق البردي الحقيقي (اختيارية)\", \"الإكراميات\"]}, \"62\": {\"title\": \"رحلة سفاري البيتش باجي (ساعتين) في مرسى علم\", \"short_description\": \"استمتع بجولة قيادة مثيرة وممتعة بالبيتش باجي (كواد) لمدة ساعتين كاملتين على الشاطئ وبين دروب جبال مرسى علم، مع وقفة في ساحة الجمال وركوب الجمل البدوي.\", \"description\": \"<h3>نظرة عامة</h3>\\n<p>انطلق في جولة قيادة حماسية وممتعة بالبيتش باجي (الرباعي) لمدة ساعتين كاملتين لاستكشاف جمال الطبيعة الصحراوية الساحرة في مرسى علم. تبدأ الجولة بالانتقال من فندقك لمخيم السفاري لتلقي تعليمات التشغيل والسلامة. ننطلق بالدراجات الرباعية في دروب الصحراء الجبلية الوعرة، متأملين التلال والجبال والوديان الطبيعية الخلابة، مع القيادة بمحاذاة شاطئ البحر الأحمر للاستمتاع بنسيم البحر والرمال الذهبية. نتوقف في ساحة الجمال (Camel Yard) للاستراحة وتناول الشاي البدوي الدافئ تحت الخيمة التقليدية، مع فرصة لتجربة ركوب الجمل البدوي والتقاط أجمل الصور التذكارية بملابس بدوية تقليدية، وفرصة طباعة صورك على ورق البردي الحقيقي كتذكار فريد قبل العودة.</p>\\n<h3>أبرز مميزات الرحلة</h3>\\n<ul>\\n  <li>جولة قيادة بالبيتش باجي (كواد) لمدة ساعتين كاملتين على الساحل والصحراء.</li>\\n  <li>استكشاف دروب الجبال والوديان الطبيعية الخلابة لمرسى علم.</li>\\n  <li>وقفة استراحة وتناول الشاي البدوي في ساحة الجمال البدوية.</li>\\n  <li>تجربة ركوب الجمل البدوي والتقاط الصور التذكارية الفريدة.</li>\\n  <li>فرصة طباعة الصور على ورق البردي الحقيقي (اختيارية) وانتقالات متضمنة.</li>\\n</ul>\", \"included\": [\"الانتقال من وإلى الفندق بمرسى علم بسيارة خاصة\", \"جولة قيادة بالبيتش باجي (الرباعية) لمدة ساعتين كاملتين\", \"ركوب الجمل البدوي بساحة الجمال\", \"شاي بدوي دافئ ومياه معدنية متضمنة\"], \"excluded\": [\"النظارات الشمسية والوشاح البدوي\", \"أدوات السنوركل (الماسك والزعانف) للرحلة البحرية\", \"المأكولات الإضافية والمشتريات والمشروبات الغازية\", \"طباعة الصور التذكارية على ورق البردي الحقيقي (اختيارية)\", \"الإكراميات\"]}}', true);

