        $services = DB::table('services')->whereBetween('id', [20, 41])->get();
        foreach ($services as $s) {
            $en = DB::table('service_translations')->where('service_id', $s->id)->where('locale', 'en')->first();
            $ar = DB::table('service_translations')->where('service_id', $s->id)->where('locale', 'ar')->first();
            
            if (!$en || !$ar) continue;
            
            $arUpdated = [];
            
            // Translate included if it is currently matching English
            $enInc = json_decode($en->included, true) ?? [];
            $arInc = json_decode($ar->included, true) ?? [];
            if ($enInc === $arInc && count($enInc) > 0) {
                $translatedInc = [];
                foreach ($enInc as $item) {
                    $trimmed = trim($item);
                    $translatedInc[] = isset($oldMapping[$trimmed]) ? $oldMapping[$trimmed] : $item;
                }
                $arUpdated['included'] = json_encode($translatedInc, JSON_UNESCAPED_UNICODE);
            }
            
            // Translate excluded if it is currently matching English
            $enExc = json_decode($en->excluded, true) ?? [];
            $arExc = json_decode($ar->excluded, true) ?? [];
            if ($enExc === $arExc && count($enExc) > 0) {
                $translatedExc = [];
                foreach ($enExc as $item) {
                    $trimmed = trim($item);
                    $translatedExc[] = isset($oldMapping[$trimmed]) ? $oldMapping[$trimmed] : $item;
                }
                $arUpdated['excluded'] = json_encode($translatedExc, JSON_UNESCAPED_UNICODE);
            }
            
            if (!empty($arUpdated)) {
                $arUpdated['updated_at'] = now();
                DB::table('service_translations')
                    ->where('id', $ar->id)
                    ->update($arUpdated);
            }
        }
